CREATE TABLE IF NOT EXISTS data_classification_policies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,code text NOT NULL,name text NOT NULL,description text NOT NULL DEFAULT '',entity_type text NOT NULL,classification_level text NOT NULL DEFAULT 'internal',pii boolean NOT NULL DEFAULT false,financial_data boolean NOT NULL DEFAULT false,health_data boolean NOT NULL DEFAULT false,status text NOT NULL DEFAULT 'active',metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE (tenant_id, code));
CREATE TABLE IF NOT EXISTS data_retention_policies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,code text NOT NULL,name text NOT NULL,description text NOT NULL DEFAULT '',entity_type text NOT NULL,retention_days integer NOT NULL DEFAULT 2555,action text NOT NULL DEFAULT 'archive',status text NOT NULL DEFAULT 'active',requires_approval boolean NOT NULL DEFAULT true,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE (tenant_id, code));
CREATE TABLE IF NOT EXISTS legal_holds (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,name text NOT NULL,description text NOT NULL DEFAULT '',entity_type text NOT NULL,entity_id text NOT NULL DEFAULT '',status text NOT NULL DEFAULT 'active',reason text NOT NULL DEFAULT '',created_by text NOT NULL DEFAULT '',released_by text NOT NULL DEFAULT '',released_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS purge_jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,entity_type text NOT NULL,retention_policy_id uuid,action text NOT NULL DEFAULT 'archive',status text NOT NULL DEFAULT 'planned',planned_by text NOT NULL DEFAULT '',approved_by text NOT NULL DEFAULT '',approved_at timestamptz,started_at timestamptz,completed_at timestamptz,candidate_count integer NOT NULL DEFAULT 0,processed_count integer NOT NULL DEFAULT 0,failed_count integer NOT NULL DEFAULT 0,cutoff_date date,failure_reason text NOT NULL DEFAULT '',metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS governance_decisions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,entity_type text NOT NULL,entity_id text NOT NULL DEFAULT '',action text NOT NULL,result text NOT NULL,reason text NOT NULL DEFAULT '',policy_id text NOT NULL DEFAULT '',decided_by text NOT NULL DEFAULT '',decided_at timestamptz NOT NULL,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_data_classification_tenant_entity ON data_classification_policies (tenant_id, entity_type, status);
CREATE INDEX IF NOT EXISTS idx_data_retention_tenant_entity ON data_retention_policies (tenant_id, entity_type, status);
CREATE INDEX IF NOT EXISTS idx_legal_holds_tenant_entity ON legal_holds (tenant_id, entity_type, entity_id, status);
CREATE INDEX IF NOT EXISTS idx_purge_jobs_tenant_entity ON purge_jobs (tenant_id, entity_type, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_governance_decisions_tenant_entity ON governance_decisions (tenant_id, entity_type, entity_id, decided_at DESC);
